function storedLocale(): Locale {
  if (typeof window === "undefined") return "ja";
  try {
    const stored = window.localStorage.getItem(STORAGE_KEY);
    return stored === "en" || stored === "ja" ? stored : preferredBrowserLocale(window.navigator);
  } catch {
    return preferredBrowserLocale(window.navigator);
  }
}

export function preferredBrowserLocale(browser: Pick<Navigator, "language" | "languages"> | undefined): Locale {
  const languages = browser?.languages?.length ? browser.languages : browser?.language ? [browser.language] : [];
  for (const language of languages) {
    const normalized = language.toLocaleLowerCase();
    if (normalized.startsWith("ja")) return "ja";
    if (normalized.startsWith("en")) return "en";
  }
  return "en";
}

export const locale = signal<Locale>(storedLocale());

export function setLocale(next: Locale): void {
  locale.value = next;
  if (typeof document !== "undefined") document.documentElement.lang = next;
  if (typeof window !== "undefined") {
    try { window.localStorage.setItem(STORAGE_KEY, next); } catch { /* Preferences may be blocked. */ }
  }
}

export function initializeI18n(): void {
  if (typeof document !== "undefined") document.documentElement.lang = locale.value;
}

export function t(key: TranslationKey, values?: Record<string, string | number>): string {
  let result: string = (locale.value === "en" ? en : ja)[key];
  if (!values) return result;
  for (const [name, value] of Object.entries(values)) result = result.replaceAll(`{${name}}`, String(value));
  return result;
}

export function chatSessionTitle(session: Pick<ChatSession, "title" | "titlePresentation">): string {
  return session.titlePresentation === "new-chat" ? t("chat.newTitle") : session.title;
}

export function chatMessageBody(message: Pick<ChatMessage, "body" | "presentation">): string {
  if (message.presentation?.kind !== "tool-fallback") return message.body;
  const name = message.presentation.name ?? t("chat.tool");
  return t(message.presentation.phase === "complete" ? "chat.toolComplete" : "chat.toolRunning", { name });
}

export type RuntimeMessage =
  | { source: "office"; key: TranslationKey; values?: Record<string, string | number> | undefined }
  | { source: "upstream"; text: string };

export function officeMessage(key: TranslationKey, values?: Record<string, string | number>): RuntimeMessage {
  return { source: "office", key, ...(values ? { values } : {}) };
}

export function upstreamMessage(text: string): RuntimeMessage {
  return { source: "upstream", text };
}

